func gcd_safe(a: Int64, b: Int64): Int64 {
    var aa = a
    var bb = b
    aa = aa.abs
    bb = bb.abs
    if aa == 0 && bb == 0 {
        return 1
    }
    while bb != 0 {
        let temp = bb
        bb = aa % bb
        aa = temp
    }
    return aa
}

func solve(points: Array<Array<Int64>>): Int64 {
    let n = points.size
    var slope_groups = {} as Map< (Int64, Int64), Map< (Int64, Int64, Int64), Int64 > >

    for i in 0 to n-1 {
        for j in i+1 to n-1 {
            let x1 = points[i][0]
            let y1 = points[i][1]
            let x2 = points[j][0]
            let y2 = points[j][1]
            let dx = x2 - x1
            let dy = y2 - y1

            if dx == 0 && dy == 0 {
                continue
            }

            let abs_dx = dx.abs
            let abs_dy = dy.abs
            let g_slope = gcd_safe(abs_dx, abs_dy)
            var dx_norm = dx
            var dy_norm = dy
            if g_slope > 0 {
                dx_norm = dx / g_slope
                dy_norm = dy / g_slope
            }

            if dy_norm < 0 {
                dx_norm = -dx_norm
                dy_norm = -dy_norm
            } else if dy_norm == 0 && dx_norm < 0 {
                dx_norm = -dx_norm
            }

            let slope_key = (dx_norm, dy_norm)

            let a = dy
            let b = -dx
            let c = dx * y1 - dy * x1

            let abs_a = a.abs
            let abs_b = b.abs
            let abs_c = c.abs
            let g_line = gcd_safe(gcd_safe(abs_a, abs_b), abs_c)
            var a_val = a
            var b_val = b
            var c_val = c
            if g_line > 0 {
                a_val = a / g_line
                b_val = b / g_line
                c_val = c / g_line
            }

            if a_val < 0 {
                a_val = -a_val
                b_val = -b_val
                c_val = -c_val
            } else if a_val == 0 {
                if b_val < 0 {
                    b_val = -b_val
                    c_val = -c_val
                } else if b_val == 0 {
                    if c_val < 0 {
                        c_val = -c_val
                    }
                }
            }

            let line_key = (a_val, b_val, c_val)

            if !slope_groups.contains(slope_key) {
                slope_groups[slope_key] = {} as Map< (Int64, Int64, Int64), Int64 >
            }
            let inner = slope_groups[slope_key]
            inner[line_key] = inner.get(line_key, 0) + 1
            slope_groups[slope_key] = inner
        }
    }

    var C : Int64 = 0
    for group in slope_groups.values {
        var total_in_slope : Int64 = 0
        for count in group.values {
            C += total_in_slope * count
            total_in_slope += count
        }
    }

    var midpoint_sums = {} as Map< (Int64, Int64), Int64 >
    for i in 0 to n-1 {
        for j in i+1 to n-1 {
            let x1 = points[i][0]
            let y1 = points[i][1]
            let x2 = points[j][0]
            let y2 = points[j][1]
            let sx = x1 + x2
            let sy = y1 + y2
            midpoint_sums[(sx, sy)] = midpoint_sums.get((sx, sy), 0) + 1
        }
    }

    var P : Int64 = 0
    for count in midpoint_sums.values {
        if count >= 2 {
            P += count * (count - 1) // 2
        }
    }

    return C - P
}
