    if (a < 0) {
        a = -a;
    }
    if (b < 0) {
        b = -b;
    }
    if (a == 0 && b == 0) {
        return 1;
    }
    while (b != 0) {
        let t = a % b;
        a = b;
        b = t;
    }
    return a;
}

