            } else {
                if (dx < 0) {
                    dx = -dx;
                    dy = -dy;
                }
                let g = gcd(dx, abs(dy));
                dx = dx // g;
                dy = dy // g;
                slope = [dx, dy];
            }
            if (!map_slope.has(slope)) {
                map_slope.set(slope, []);
            }
            let list = map_slope.get(slope);
            list.push([i, j]);
            map_slope.set(slope, list);
        }
    }

    let F: Int64 = 0;
    for (let slope of map_slope.keys()) {
        let segments = map_slope.get(slope);
        let m = segments.length;
        if (m < 2) {
            continue;
        }
        let dx = slope[0];
        let dy = slope[1];
        if (m < THRESHOLD) {
            for (let i = 0; i < m; i++) {
                let seg1 = segments[i];
