                } else {
                    intercept = dx * y - dy * x;
                }
                if (!interceptGroups.has(intercept)) {
                    interceptGroups.set(intercept, []);
                }
                let list = interceptGroups.get(intercept);
                list.push(seg);
                interceptGroups.set(intercept, list);
            }
            let groups = interceptGroups.values();
            let ng = groups.length;
            let sizes = Array<Int64>();
            let freqs = Array<Array<Int64>>();
            for (let group of groups) {
                let size = group.length;
                sizes.push(size);
                let freq_arr = Array<Int64>(n).fill(0);
                for (let seg of group) {
                    let i = seg[0];
                    let j = seg[1];
                    freq_arr[i] += 1;
                    freq_arr[j] += 1;
