            for (let i = 0; i < ng; i++) {
                for (let j = i + 1; j < ng; j++) {
                    let size_i = sizes[i];
                    let size_j = sizes[j];
                    let total_pairs = size_i * size_j;
                    let non_disjoint: Int64 = 0;
                    for (let v = 0; v < n; v++) {
                        non_disjoint += freqs[i][v] * freqs[j][v];
                    }
                    F += total_pairs - non_disjoint;
                }
            }
        }
    }

    let G: Int64 = 0;
    let map_mid = Map<Array<Int64>, Array<Array<Int64>>>();
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            let x1 = points[i][0];
            let y1 = points[i][1];
            let x2 = points[j][0];
            let y2 = points[j][1];
