func solve(points: Array<Array<Int64>>) -> Int64 {
    func gcd(_ aIn: Int64, _ bIn: Int64) -> Int64 {
        var a = aIn
        var b = bIn
        if a < 0 { a = -a }
        if b < 0 { b = -b }
        if a == 0 && b == 0 {
            return 1
        }
        if a == 0 {
            return b
        }
        if b == 0 {
            return a
        }
        if a < b {
            let temp = a
            a = b
            b = temp
        }
        var r = a % b
        var currentA = a
        var currentB = b
        while r != 0 {
            currentA = currentB
            currentB = r
            r = currentA % currentB
        }
        return currentB
    }

    let n = points.count
    var slopes_dict: [ (dx: Int64, dy: Int64) : [(Int, Int)] ] = [:]
    var midpoints_dict: [ (x_sum: Int64, y_sum: Int64) : [(Int, Int)] ] = [:]

    for i in 0..<n {
        for j in (i+1)..<n {
            let p1 = points[i]
            let p2 = points[j]
            var dx = p1[0] - p2[0]
            var dy = p1[1] - p2[1]

            var slope_key: (dx: Int64, dy: Int64)
            if dx == 0 && dy == 0 {
                continue
            } else if dx == 0 {
                slope_key = (0, 1)
            } else {
                let flip = dx < 0
                if flip {
                    dx = -dx
                    dy = -dy
                }
                let g = gcd(dx, abs(dy))
                if g == 0 {
                    slope_key = (dx, dy)
                } else {
                    slope_key = (dx/g, dy/g)
                }
            }
            slopes_dict[slope_key, default: []].append((i, j))

            let mid_key = (p1[0] + p2[0], p1[1] + p2[1])
            midpoints_dict[mid_key, default: []].append((i, j))
        }
    }

    var total_trap: Int64 = 0
    for (_, segments) in slopes_dict {
        let k = segments.count
        var deg: [Int: Int] = [:]
        for seg in segments {
            deg[seg.0, default: 0] += 1
            deg[seg.1, default: 0] += 1
        }
        var bad_pairs = 0
        for (_, cnt) in deg {
            bad_pairs += (cnt * (cnt - 1)) / 2
        }
        let total_pairs = (k * (k - 1)) / 2
        total_trap += Int64(total_pairs - bad_pairs)
    }

    var para_count: Int64 = 0
    for (_, segments) in midpoints_dict {
        let k = segments.count
        para_count += Int64(k * (k - 1) / 2)
    }

    return total_trap - para_count
}
```

### Explanation
1. **gcd Function**: Computes the greatest common divisor of two integers, used to normalize slope vectors.
2. **Slope and Midpoint Dictionaries**: These dictionaries group segments by their normalized slopes and midpoints, respectively.
3. **Trapezoid Count**: For each slope group, the total possible pairs of segments is calculated. Pairs sharing a vertex are subtracted to count only disjoint segments, which can form trapezoids.
4. **Parallelogram Adjustment**: The number of parallelograms (counted twice in trapezoid groups) is determined by segment pairs sharing the same midpoint (indicating diagonals). The final count adjusts for this by subtracting the parallelogram count.
5. **Efficiency**: The solution efficiently processes all pairs of points, leveraging dictionary grouping and combinatorial counting to handle constraints within feasible complexity.
